const event = $input.first().json;
const record = event.record || event.new || {};
const oldRecord = event.old || {};
const table = event.table || '';
const op = event.type || event.op || 'INSERT';

// Map table names to entity types
const entityTypeMap = {
  'quotations': 'quotation',
  'customers': 'customer',
  'subscriptions': 'subscription',
  'work_orders': 'work_order',
  'suppliers': 'supplier',
  'supplier_purchases': 'supplier_purchase',
  'marketing_campaigns': 'marketing_campaign',
  'pricing_materials': 'pricing',
  'pricing_services': 'pricing',
  'planner_tasks': 'planner_task',
  'pnl_expenses': 'pnl_expense',
  'pnl_revenues': 'pnl_revenue'
};

const entityType = entityTypeMap[table] || table || 'unknown';

// Build action string
const actionMap = {
  'INSERT': 'created',
  'UPDATE': 'updated',
  'DELETE': 'deleted'
};
const actionVerb = actionMap[op] || op.toLowerCase();

// Build entity ID
const entityId = record.id || record.quote_no || record.name || JSON.stringify(record).slice(0,50);

// Build meaningful detail
let detail = '';
if (table === 'quotations') {
  const statusChange = oldRecord.status && oldRecord.status !== record.status ? ` (status: ${oldRecord.status} → ${record.status})` : '';
  detail = `Quotation ${record.quote_no} ${actionVerb}${statusChange}`;
} else if (table === 'customers') {
  detail = `Customer ${record.name || record.email} ${actionVerb}`;
} else if (table === 'work_orders') {
  detail = `Work Order "${record.title}" ${actionVerb} in column "${record.kanban_col || ''}"`;
} else if (table === 'subscriptions') {
  detail = `Subscription ${record.plan_name} ${actionVerb} for ${record.customer_id?.slice(0,8)}`;
} else if (table === 'marketing_campaigns') {
  detail = `Campaign "${record.name}" ${actionVerb} (${record.status || ''})`;
} else {
  detail = `${table} record ${actionVerb}`;
}

return [{
  action: `${table?.replace('_','')}_${actionVerb}`,
  entity_type: entityType,
  entity_id: entityId,
  detail: detail,
  created_at: new Date().toISOString()
}];
